import java.util.Scanner;

public class BufferOverflowSecure {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int bufferSize = 10;

        // Ensure that user input does not exceed buffer size
        String truncatedInput = userInput.substring(0, Math.min(userInput.length(), bufferSize));

        char[] buffer = new char[bufferSize];

        // Copy truncated user input into buffer
        truncatedInput.getChars(0, truncatedInput.length(), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

